CREATE TABLE IF NOT EXISTS shard_metadata (family TEXT NOT NULL CHECK (family = 'REMOTE_POSTS'), schema_version INTEGER NOT NULL, applied_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, PRIMARY KEY (family, schema_version));
INSERT OR IGNORE INTO shard_metadata (family, schema_version) VALUES ('REMOTE_POSTS', 1);
CREATE TABLE IF NOT EXISTS remote_post_records (id TEXT PRIMARY KEY, account_id TEXT NOT NULL, uri TEXT NOT NULL UNIQUE, activity_uri TEXT UNIQUE, payload_json TEXT NOT NULL, published_at_raw TEXT, published_at_ms INTEGER, received_at_ms INTEGER NOT NULL, sort_at_ms INTEGER NOT NULL, source_version INTEGER NOT NULL DEFAULT 1, tombstoned_at TEXT, deleted_at TEXT, created_at TEXT NOT NULL, updated_at TEXT NOT NULL);
CREATE INDEX IF NOT EXISTS idx_remote_post_records_account_created ON remote_post_records (account_id, sort_at_ms DESC, id DESC);
CREATE TABLE IF NOT EXISTS applied_operations (operation_id TEXT PRIMARY KEY, aggregate_version INTEGER, command_type TEXT NOT NULL, applied_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS shard_outbox (event_id TEXT PRIMARY KEY, operation_id TEXT NOT NULL, destination TEXT NOT NULL, event_type TEXT NOT NULL, payload_json TEXT NOT NULL, attempts INTEGER NOT NULL DEFAULT 0, next_attempt_at INTEGER, dispatched_at TEXT, created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE INDEX IF NOT EXISTS idx_shard_outbox_pending ON shard_outbox (dispatched_at, next_attempt_at, created_at);
